// Get the article text from the previous step
const rawText = $json.article_text || $json.body || $json.text || "";

// Remove HTML tags (like <p>, <h1>, <br> etc)
const cleanText = rawText
  .replace(/<[^>]*>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/\s+/g, ' ')
  .trim();

// Send the clean text to the next node
return { article_text: cleanText };

// Get Gemini's response text
const raw = $json.text || $json.content || $json.message || $json.output || "";

// Split into three sections using our markers
const linkedin = raw.split('---LINKEDIN---')[1]?.split('---TWITTER---')[0]?.trim() || "LinkedIn content not found";
const twitter  = raw.split('---TWITTER---')[1]?.split('---EMAIL---')[0]?.trim() || "Twitter content not found";
const email    = raw.split('---EMAIL---')[1]?.trim() || "Email content not found";

// Return all three as separate labelled outputs
return {
  linkedin_post:    linkedin,
  twitter_thread:   twitter,
  email_teaser:     email,
  generated_at:     new Date().toISOString()
};
